code.C:
#include <stdio.h>

long long gcd_ll(long long a, long long b) {
    while (b) {
        long long t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, K;
        scanf("%lld %lld", &N, &K);
        long long g = gcd_ll(N, K);
        printf("%lld\n", N / g);
    }
    return 0;
}

